mapper.select:
SELECT COUNT(*)
FROM tb_member
WHERE member_id = #{memberId}

mapper.update:
UPDATE tb_member
SET
    member_name = #{memberName},
    member_addr = #{memberAddr},
    member_tel = #{memberTel}
WHERE member_id = #{memberId}

UPDATE tb_member
SET member_pw = #{memberPw}
WHERE member_id = #{memberId}
